Praktyczny przykład: Walidacja formularza
document.querySelector('#form-rejestracja').addEventListener('submit', (e) =&gt; {
    const email = document.querySelector('#email').value;
    const haslo = document.querySelector('#haslo').value;
    const bledy = [];

    if (!email.includes('@')) {
        bledy.push('Podaj prawidłowy adres e-mail');
    }

    if (haslo.length &lt; 8) {
        bledy.push('Hasło musi mieć co najmniej 8 znaków');
    }

    if (bledy.length &gt; 0) {
        e.preventDefault(); // Zablokuj wysłanie formularza
        const kontenerBledow = document.querySelector('#bledy');
        kontenerBledow.innerHTML = bledy
            .map(b =&gt; `&lt;p class="blad"&gt;${b}&lt;/p&gt;`)
            .join('');
    }
});

10. Fetch + DOM: Łączymy wszystko w całość
Na Wykładzie 1 widzieliśmy, jak Frontend rozmawia z Backendem. Teraz połączymy pobieranie danych z API z dynamicznym wyświetlaniem ich na stronie — bez przeładowania:
&lt;!DOCTYPE html&gt;
&lt;html lang="pl"&gt;
&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;meta name="viewport" content="width=device-width, initial-scale=1.0"&gt;
    &lt;title&gt;Lista studentów&lt;/title&gt;
    &lt;style&gt;
        .student-card {
            border: 1px solid #ddd;
            padding: 15px;
            margin: 10px 0;
            border-radius: 8px;
        }
        .loading { color: #888; font-style: italic; }
        .error { color: red; }
    &lt;/style&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;h1&gt;Lista studentów&lt;/h1&gt;
    &lt;button id="pobierz-btn"&gt;Pobierz z serwera&lt;/button&gt;
    &lt;div id="kontener"&gt;&lt;/div&gt;

    &lt;script&gt;
    const kontener = document.querySelector('#kontener');
    const przycisk = document.querySelector('#pobierz-btn');

    przycisk.addEventListener('click', async () =&gt; {
        // 1. Pokaż stan ładowania
        kontener.innerHTML = '&lt;p class="loading"&gt;Ładowanie danych...&lt;/p&gt;';
        przycisk.disabled = true;

        try {
            // 2. Pobierz dane z API (GET)
            const response = await fetch('http://localhost:5000/api/studenci');

            if (!response.ok) {
                throw new Error(`Serwer zwrócił błąd ${response.status}`);
            }

            const studenci = await response.json();

            // 3. Zbuduj HTML z danych i wstaw do DOM
            if (studenci.length === 0) {
                kontener.innerHTML = '&lt;p&gt;Brak studentów w bazie.&lt;/p&gt;';
            } else {
                kontener.innerHTML = studenci
                    .map(s =&gt; `
                        &lt;article class="student-card"&gt;
                            &lt;h3&gt;${s.imie}&lt;/h3&gt;
                            &lt;p&gt;Kierunek: ${s.kierunek}&lt;/p&gt;
                        &lt;/article&gt;
                    `)
                    .join('');
            }

        } catch (error) {
            // 4. Obsługa błędów
            kontener.innerHTML = `&lt;p class="error"&gt;Błąd: ${error.message}&lt;/p&gt;`;
        } finally {
            przycisk.disabled = false;
        }
    });
    &lt;/script&gt;
&lt;/body&gt;
&lt;/html&gt;
Ten prosty przykład demonstruje cały cykl SPA z Wykładu 1:

Przeglądarka NIE przeładowuje strony
JavaScript wysyła żądanie GET do API
Serwer odpowiada JSON-em (nie HTML-em!)
JavaScript sam buduje HTML z otrzymanych danych i wstawia go do DOM

11. Wysyłanie danych: POST z fetch
Na Wykładzie 1 widzieliśmy prosty POST. Oto pełna wersja z walidacją i obsługą odpowiedzi:
async function dodajStudenta(imie, kierunek) {
    try {
        const response = await fetch('http://localhost:5000/api/studenci', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                imie: imie,
                kierunek: kierunek
            })
        });

        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.message || `HTTP ${response.status}`);
        }

        const wynik = await response.json();
        console.log("Dodano studenta z ID:", wynik.id);
        return wynik;

    } catch (error) {
        console.error("Nie udało się dodać studenta:", error.message);
        throw error; // Przekaż dalej, niech wywołujący zdecyduje co z tym zrobić
    }
}

// Obsługa formularza
document.querySelector('#form-dodaj').addEventListener('submit', async (e) =&gt; {
    e.preventDefault(); // Nie przeładowuj strony!

    const imie = document.querySelector('#imie').value.trim();
    const kierunek = document.querySelector('#kierunek').value.trim();

    if (!imie || !kierunek) {
        alert("Wypełnij wszystkie pola");
        return;
    }

    try {
        await dodajStudenta(imie, kierunek);
        alert("Student dodany!");
        e.target.reset(); // Wyczyść formularz
    } catch (err) {
        alert("Błąd: " + err.message);
    }
});
Porównaj z Wykładem 1 — ta sama logika, ale z poprawną obsługą błędów, walidacją i async/await zamiast łańcuchów .then().

12. Klasy w JavaScript (ES6)
JavaScript ma klasy od ES6. Składnia jest podobna do PHP z Wykładu 4:
class Produkt {
    // Pola prywatne (ES2022) — zaczynają się od #
    #nazwa;
    #cena;
    #ilosc;

    constructor(nazwa, cena, ilosc = 0) {
        this.#nazwa  = nazwa;
        this.#cena   = cena;
        this.#ilosc  = ilosc;
    }

    // Gettery
    get nazwa() { return this.#nazwa; }
    get cena()  { return this.#cena; }

    jestDostepny() {
        return this.#ilosc &gt; 0;
    }

    sprzedaj(ile = 1) {
        if (ile &gt; this.#ilosc) {
            throw new Error("Brak na stanie");
        }
        this.#ilosc -= ile;
    }

    // Metoda do serializacji (analogia do toArray() z PHP)
    toJSON() {
        return {
            nazwa:    this.#nazwa,
            cena:     this.#cena,
            ilosc:    this.#ilosc,
            dostepny: this.jestDostepny()
        };
    }

    // Metoda statyczna — wywoływana na klasie, nie na obiekcie
    static fromJSON(json) {
        return new Produkt(json.nazwa, json.cena, json.ilosc);
    }
}

// Użycie
const laptop = new Produkt("ThinkPad", 5499, 10);
console.log(laptop.nazwa);          // "ThinkPad" (getter)
console.log(laptop.jestDostepny()); // true

// Serializacja do JSON (np. wysyłka do API)
const json = JSON.stringify(laptop.toJSON());
// {"nazwa":"ThinkPad","cena":5499,"ilosc":10,"dostepny":true}

Dziedziczenie
class ProduktFizyczny extends Produkt {
    #waga;

    constructor(nazwa, cena, ilosc, waga) {
        super(nazwa, cena, ilosc); // Wywołaj konstruktor rodzica
        this.#waga = waga;
    }

    kosztDostawy() {
        return this.#waga * 5; // 5 zł za kg
    }

    toJSON() {
        return {
            ...super.toJSON(),       // Spread: weź pola z rodzica
            waga:    this.#waga,
            dostawa: this.kosztDostawy()
        };
    }
}

const laptop = new ProduktFizyczny("ThinkPad", 5499, 10, 1.2);
console.log(laptop.kosztDostawy()); // 6

13. Moduły (import/export)
W większych projektach kod dzielimy na pliki (moduły). Każdy moduł eksportuje to, co chce udostępnić, i importuje to, czego potrzebuje:
// ═══ plik: models/Produkt.js ═══
export class Produkt {
    constructor(nazwa, cena) {
        this.nazwa = nazwa;
        this.cena  = cena;
    }
}

export function formatujCene(cena) {
    return `${cena.toFixed(2)} zł`;
}

// ═══ plik: services/api.js ═══
const API_URL = 'http://localhost:5000/api';

export async function pobierzProdukty() {
    const res = await fetch(`${API_URL}/produkty`);
    return res.json();
}

export async function dodajProdukt(dane) {
    const res = await fetch(`${API_URL}/produkty`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(dane)
    });
    return res.json();
}

// ═══ plik: main.js ═══
import { Produkt, formatujCene } from './models/Produkt.js';
import { pobierzProdukty } from './services/api.js';

const produkty = await pobierzProdukty();
produkty.forEach(p =&gt; {
    console.log(`${p.nazwa}: ${formatujCene(p.cena)}`);
});
Aby użyć modułów w HTML:
&lt;!-- type="module" włącza obsługę import/export --&gt;
&lt;script type="module" src="main.js"&gt;&lt;/script&gt;

K-S: Kod po stronie klienta (Frontend)
To wszystko, co działa bezpośrednio na komputerze użytkownika (w jego przeglądarce).
HTML (HyperText Markup Language): Szkielet i struktura. Definiuje, gdzie jest nagłówek, gdzie akapit, a gdzie formularz. HTML odpowiada za to, co jest wyświetlane.
&lt;!DOCTYPE html&gt;
&lt;html lang="pl"&gt;
&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;title&gt;Wykład: Klient i Serwer w akcji&lt;/title&gt;
    &lt;link rel="stylesheet" href="style.css"&gt;
&lt;/head&gt;
&lt;body&gt;

    &lt;h1&gt;Pierwszy program&lt;/h1&gt;
    &lt;p&gt;Hello World&lt;/p&gt;

&lt;/body&gt;
&lt;/html&gt;
CSS (Cascading Style Sheets): Odpowiada za to, jak strona wygląda (kolory, animacje, układ responsywny na telefony).
body { 
    font-family: sans-serif; 
    padding: 30px; 
    max-width: 600px; 
    margin: 0 auto; 
}

button { 
    padding: 10px 15px; 
    font-size: 16px; 
    cursor: pointer; 
}
JavaScript (JS): Język programowania, który pozwala stronie żyć. Reaguje na kliknięcia, wysyła dane w tle, dynamicznie zmienia zawartość bez przeładowywania całej strony.
document.getElementById('pobierz-btn').addEventListener('click', function() {
    fetch('https://serwer-uczelni.pw.edu.pl/api/studenci')
        .then(odpowiedz =&gt; odpowiedz.json()) 
        .then(dane =&gt; {
            console.log("Sukces! Pobrane dane to:", dane);
        });
});

Backend - kod po stronie Serwera
To “mózg” operacji, ukryty przed oczami użytkownika. Szczególnie w aplikacjach korporacyjnych (Enterprise) to tutaj dzieje się magia.

Zadania:

Walidacja danych (klientowi nigdy nie ufamy!),
operacje na bazie danych (SQL/NoSQL),
integracje z zewnętrznymi systemami (np. systemem płatności BLIK),
zarządzanie sesjami i bezpieczeństwem.


Technologie: W odróżnieniu od przeglądarki (która rozumie tylko JS/WebAssembly), na serwerze możemy pisać w czym chcemy: Java (Spring Boot), C# (.NET), Python (Django/FastAPI), PHP czy Node.js.
&lt;?php
echo "Hello, world!!!";
?&gt;
from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/powitanie')
def powitanie():
    # Zwracamy słownik, który Flask sam zamieni na JSON
    return jsonify({"wiadomosc": "Witaj z serwera Python (Flask)!"})

if __name__ == '__main__':
    app.run(port=5000)
using Genie, Genie.Renderer.Json

route("/api/powitanie") do
  json(Dict("wiadomosc" =&gt; "Witaj z serwera Julia!"))
end

up(8000)
const express = require('express');
const app = express();

app.get('/api/powitanie', (req, res) =&gt; {
    // Odpowiadamy formatem JSON
    res.json({ wiadomosc: "Witaj z serwera Node.js!" });
});

app.listen(3000, () =&gt; {
    console.log('Serwer działa na porcie 3000');
});

Anatomia komunikacji w sieci: Żądanie, Odpowiedź i URL
Aby Klient i Serwer mogli ze sobą rozmawiać, używają protokołu HTTP. Ta komunikacja przypomina trochę rozmowę w restauracji i opiera się na trzech głównych filarach:

URL (Uniform Resource Locator): To dokładny adres zasobu (np. http://moj-serwer.pl/api/studenci). W naszej metaforze to wskazanie palcem konkretnego dania w menu.
Żądanie (Request): Wiadomość wysyłana przez Klienta (przeglądarkę) do Serwera. Zawiera informację, czego Klient chce (metoda) i pod jakim adresem (URL).
Odpowiedź (Response): Wiadomość zwrotna od Serwera. Zawiera tzw. status (np. 200 OK – “mam to dla ciebie”, albo 404 Not Found – “nie ma takiego adresu”) oraz same dane (np. w formacie JSON).


Metoda GET: Pobieranie danych przez przeglądarkę
Najbardziej podstawową metodą HTTP jest GET (z ang. pobierz). Służy ona wyłącznie do odczytywania danych.
Co ważne: Za każdym razem, gdy wpisujesz adres w pasku przeglądarki (np. google.com) i wciskasz Enter, Twoja przeglądarka wysyła w tle żądanie GET.
Zatem jeśli nasz serwer w Pythonie działa lokalnie, wcale nie potrzebujemy specjalnego kodu na Froncie, by go przetestować. Wystarczy otworzyć nową kartę w Chrome i wpisać: http://localhost:5000/api/powitanie Przeglądarka zapyta (GET), a serwer odpowie, wyświetlając na ekranie surowy tekst JSON.


Zmienność odpowiedzi: Serwer czyta URL
Prawdziwa potęga Backendu polega na tym, że serwer nie musi mieć gotowego pliku dla każdego możliwego adresu. Może traktować fragmenty adresu URL jako zmienne i na ich podstawie generować odpowiedź w locie.
Załóżmy, że chcemy pobrać dane konkretnego studenta. Wpisujemy w przeglądarce: http://localhost:5000/api/student/2
Oto jak serwer we Flasku przechwytuje tę cyfrę 2 z adresu URL i zmienia swój wynik:
from flask import Flask, jsonify

app = Flask(__name__)

# "Udawana" baza danych
baza_studentow = {
    1: {"imie": "Jan", "kierunek": "Informatyka"},
    2: {"imie": "Anna", "kierunek": "Cyberbezpieczeństwo"},
    3: {"imie": "Piotr", "kierunek": "Robotyka"}
}

# Znak &lt;int:id&gt; mówi serwerowi: "Złap liczbę z adresu URL i przekaż do funkcji"
@app.route('/api/student/&lt;int:id&gt;', methods=['GET'])
def pobierz_konkretnego_studenta(id):

    # Sprawdzamy, czy student o takim ID istnieje w naszej bazie
    if id in baza_studentow:
        # Jeśli wpiszesz /api/student/2, serwer zwróci dane Anny
        return jsonify(baza_studentow[id])
    else:
        # Jeśli wpiszesz /api/student/99, serwer zwróci błąd
        return jsonify({"blad": "Nie znaleziono studenta"}), 404

if __name__ == '__main__':
    app.run(port=5000)


Metoda POST: Wysyłanie ukrytych danych
Skoro GET potrafi przekazywać zmienne w adresie URL (np. ?szukaj=buty), dlaczego potrzebujemy czegoś innego?
Wyobraź sobie logowanie do banku. Gdybyśmy użyli metody GET, Twoje hasło wylądowałoby w pasku adresu przeglądarki (np. bank.pl/login?haslo=mojeTajneHaslo). To ogromne zagrożenie bezpieczeństwa, a ponadto adresy URL mają ograniczoną długość.
Dlatego, gdy wysyłamy nowe, poufne lub duże dane (np. formularz rejestracji, zdjęcie, wpis na blogu), używamy metody POST.
W zapytaniu POST dane nie są doklejane do adresu URL.
Są one pakowane do “brzucha” (ang. Body / Payload) żądania HTTP, który jest niewidoczny z poziomu paska przeglądarki.
Żądania POST nie da się wywołać po prostu wpisując adres w przeglądarce (wykonujemy je z poziomu kodu JavaScript po kliknięciu przycisku “Wyślij”, lub z aplikacji np. Postman).


Jak działa metoda POST w praktyce? (Kod Klienta i Serwera)
Aby przetestować metodę POST, potrzebujemy współpracy Frontendu (który wyśle dane) i Backendu (który je odbierze).
1. Kod Klienta (Frontend - HTML + JS) Zamiast wpisywać adres w przeglądarce, użytkownik wypełnia formularz i klika przycisk. Przeglądarka pakuje te dane w JSON i wysyła w tle.
&lt;input type="text" id="imie-input" placeholder="Wpisz imię"&gt;
&lt;input type="text" id="kierunek-input" placeholder="Wpisz kierunek"&gt;
&lt;button id="zapisz-btn"&gt;Zapisz na serwerze&lt;/button&gt;

&lt;script&gt;
document.getElementById('zapisz-btn').addEventListener('click', function() {
    // 1. Zbieramy dane z pól tekstowych
    const daneDoWyslania = { 
        imie: document.getElementById('imie-input').value,
        kierunek: document.getElementById('kierunek-input').value
    };

    // 2. Wysyłamy żądanie POST do API
    fetch('http://localhost:5000/api/dodaj-studenta', {
        method: 'POST', // Zmieniamy domyślne GET na POST
        headers: {
            'Content-Type': 'application/json' // Informujemy serwer: "Uwaga, leci JSON!"
        },
        body: JSON.stringify(daneDoWyslania) // Zamieniamy obiekt w tekst JSON
    })
    .then(odpowiedz =&gt; odpowiedz.json())
    .then(wynik =&gt; {
        console.log("Odpowiedź z serwera:", wynik);
        alert("Serwer zapisał: " + wynik.dodano);
    });
});
&lt;/script&gt;

2. Anatomia dokumentu HTML5
Każdy plik HTML zaczyna się od tego samego szkieletu. Przypomnijmy go z Wykładu 1 i omówmy dokładnie:
&lt;!DOCTYPE html&gt;
&lt;html lang="pl"&gt;
&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;meta name="viewport" content="width=device-width, initial-scale=1.0"&gt;
    &lt;title&gt;Moja aplikacja&lt;/title&gt;
    &lt;link rel="stylesheet" href="style.css"&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;h1&gt;Witaj na stronie!&lt;/h1&gt;
    &lt;p&gt;To jest akapit tekstu.&lt;/p&gt;
&lt;/body&gt;
&lt;/html&gt;
Co robi każda linia?

&lt;!DOCTYPE html&gt; — Deklaracja typu dokumentu. Mówi przeglądarce: “Traktuj mnie jak HTML5”. Bez tego przeglądarka wchodzi w tzw. quirks mode i renderuje stronę nieprzewidywalnie.
&lt;html lang="pl"&gt; — Element główny. Atrybut lang informuje wyszukiwarki i czytniki ekranowe, w jakim języku jest treść.
&lt;meta charset="UTF-8"&gt; — Kodowanie znaków. Bez tego polskie litery (ą, ę, ś) mogą wyświetlić się jako “krzaczki”.
&lt;meta name="viewport" ...&gt; — Kluczowa linia dla urządzeń mobilnych. Bez niej telefon wyświetli stronę jakby miał ekran desktopowy i zmniejszy ją do rozmiaru znaczka pocztowego.
&lt;head&gt; — Sekcja niewidoczna dla użytkownika. Metadane, tytuł w zakładce, linki do arkuszy CSS i skryptów.
&lt;body&gt; — Wszystko, co użytkownik widzi na ekranie.

3. Elementy semantyczne HTML5: Kod, który ma znaczenie
W starym HTML cała strona składała się z &lt;div&gt; (kontener blokowy) i &lt;span&gt; (kontener liniowy). Kod wyglądał tak:
&lt;!-- ❌ Stare podejście: "Divitis" — choroba nadmiarowych divów --&gt;
&lt;div id="header"&gt;
    &lt;div id="nav"&gt;...&lt;/div&gt;
&lt;/div&gt;
&lt;div id="content"&gt;
    &lt;div class="post"&gt;...&lt;/div&gt;
    &lt;div id="sidebar"&gt;...&lt;/div&gt;
&lt;/div&gt;
&lt;div id="footer"&gt;...&lt;/div&gt;
Problem? Przeglądarka, wyszukiwarka Google i czytnik ekranowy dla osoby niewidomej widzą jedynie stos anonimowych “pudełek” (div). Nie wiedzą, co jest menu, co artykułem, a co stopką.
HTML5 wprowadził elementy semantyczne — tagi, które opisują swoją rolę:
&lt;!-- ✅ HTML5: Kod, który mówi, czym jest --&gt;
&lt;header&gt;
    &lt;nav&gt;
        &lt;a href="/"&gt;Start&lt;/a&gt;
        &lt;a href="/about"&gt;O nas&lt;/a&gt;
        &lt;a href="/contact"&gt;Kontakt&lt;/a&gt;
    &lt;/nav&gt;
&lt;/header&gt;

&lt;main&gt;
    &lt;article&gt;
        &lt;h1&gt;Tytuł artykułu&lt;/h1&gt;
        &lt;section&gt;
            &lt;h2&gt;Sekcja pierwsza&lt;/h2&gt;
            &lt;p&gt;Treść sekcji...&lt;/p&gt;
        &lt;/section&gt;
        &lt;section&gt;
            &lt;h2&gt;Sekcja druga&lt;/h2&gt;
            &lt;p&gt;Kolejna treść...&lt;/p&gt;
        &lt;/section&gt;
    &lt;/article&gt;

    &lt;aside&gt;
        &lt;h3&gt;Powiązane artykuły&lt;/h3&gt;
        &lt;ul&gt;
            &lt;li&gt;&lt;a href="/art2"&gt;Inny artykuł&lt;/a&gt;&lt;/li&gt;
        &lt;/ul&gt;
    &lt;/aside&gt;
&lt;/main&gt;

&lt;footer&gt;
    &lt;p&gt;&copy; 2026 Moja Firma&lt;/p&gt;
&lt;/footer&gt;
Każdy z tych tagów ma konkretne znaczenie:



